DROP TABLE IF EXISTS Dresseurs;
CREATE TABLE Dresseurs (
    id_dresseur BIGINT AUTO_INCREMENT PRIMARY KEY,
    nom VARCHAR(50) NOT NULL,
    titre VARCHAR(50),
    ville_origine VARCHAR(50),
    heures_de_jeu DECIMAL(6,2),
    date_debut_aventure DATE
) ENGINE=InnoDB AUTO_INCREMENT=1000000000000000;

DROP TABLE IF EXISTS Pokedex;
CREATE TABLE Pokedex (
    numero_pokedex INT PRIMARY KEY,
    nom_espece VARCHAR(50) NOT NULL,
    type_1 VARCHAR(20) NOT NULL,
    type_2 VARCHAR(20),
    stat_base_pv INT,
    stat_base_attaque INT,
    stat_base_defense INT,
    stat_base_atq_spe INT,
    stat_base_def_spe INT,
    stat_base_vitesse INT
);

DROP TABLE IF EXISTS Captures;
CREATE TABLE Captures (
    id_capture BIGINT AUTO_INCREMENT PRIMARY KEY,
    id_dresseur BIGINT NOT NULL,
    numero_pokedex INT NOT NULL,
    surnom VARCHAR(50),
    niveau INT DEFAULT 1,
    genre CHAR(1),
    nature VARCHAR(20),
    talent VARCHAR(50),
    type_tera VARCHAR(20),
    objet_tenu VARCHAR(50),
    pokeball_utilisee VARCHAR(30),
    insigne_equipe VARCHAR(50),
    iv_pv INT,
    iv_attaque INT,
    iv_defense INT,
    iv_atq_spe INT,
    iv_def_spe INT,
    iv_vitesse INT,
    ev_pv INT DEFAULT 0,
    ev_attaque INT DEFAULT 0,
    ev_defense INT DEFAULT 0,
    ev_atq_spe INT DEFAULT 0,
    ev_def_spe INT DEFAULT 0,
    ev_vitesse INT DEFAULT 0,
    date_rencontre DATETIME,
    lieu_rencontre VARCHAR(100),
    niveau_rencontre INT,
    est_shiny BOOLEAN DEFAULT FALSE,
    FOREIGN KEY (id_dresseur) REFERENCES Dresseurs(id_dresseur),
    FOREIGN KEY (numero_pokedex) REFERENCES Pokedex(numero_pokedex)
);

ALTER TABLE Pokedex CONVERT TO CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;















